// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:30。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舞台器材區。禮堂後方。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這裡是舞台組的臨時倉庫。鐵架、燈光桁架、成捲的線材、備用音箱、折疊桌椅。空氣裡有灰塵和潤滑油的味道。鐵捲門半開著，外面的雨聲像一堵白色的牆。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越站在工作台前。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "台面上攤著一排東西。不是專業電影道具。是校慶舞台組能合理找到的東西。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一件黑雨衣。校慶當天每個舞台組志工都有一件，倉庫裡多出來的。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一件舊制服外套。從失物箱裡翻出來的，沒有人會認領。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的背包。他自己的。今天早上從宿舍帶出來的。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個舞台假人。可拆式人形支架，帆布外皮，四肢可調角度。開幕表演用的道具，表演結束就拆下來扔在倉庫角落。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "幾個裝沙的器材袋。舞台組用來壓燈架底座的。每袋大約五公斤。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的手機。他自己的。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個假相機包。用攝影背心的內袋塞了泡棉做的，外面套一個舊相機包的殼。遠看像。摸起來不像。但今晚不會有人摸到。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這些東西。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是特效。不是替身。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是校慶倉庫裡本來就有的東西。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）夠了。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把黑雨衣展開，披在舞台假人的上半身。雨衣很大，帽沿壓下來能遮住假人的臉部——假人本來就沒有臉，帆布縫出來的輪廓，在暴雨和低光裡，和一個低頭走路的人沒有區別。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "背包。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "命令式。不是請求。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言把自己的背包放到工作台上。韓越打開背包，把裡面的東西全部倒出來——筆記本、筆、學生證、一包面紙、充電線。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "手機。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言掏出手機。螢幕上還留著那則匿名訊息——第八次了。他看了一眼。然後遞給韓越。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "解鎖了嗎。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把手機塞進背包裡。背包綁在假人的背上，背帶扣緊。他又把舊制服外套套在假人外面，遮住背帶的邊緣。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝沙的器材袋塞進假人的腰部和腿部——增加重量，讓它從高處墜落的時候有足夠的質感。不是人體的質感。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不需要像人。只需要像到監控裡分不出來。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但在暴雨、停電、低畫質監控裡，沒有人能分辨五公斤沙袋和一個人的區別。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越退後一步，看了看整體效果。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "遠看可以。近看不行。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉向顧言。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "假相機包你帶。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把那個假相機包遞過來。外殼是一個舊相機包，裡面塞了泡棉，重量和真相機差不多。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）假包。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）餌。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他接過來。掛在肩上。重量不對——太輕了。但掛在肩上的形狀和真相機包一樣。在監控畫面裡，遠處校安的眼裡，在邵叔透過林主任或指揮室得到的回報裡——這就是一個相機包。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔會看見我帶著這個走向鐘樓。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會判斷——我帶著相機包，準備走鐘樓備用傳輸線。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和他被餵到的情報吻合。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）餌要像餌。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他調整了一下背帶。讓假包的位置偏高一點——和許星棠平時背真相機的習慣不同。這樣就算邵叔透過監控看到，也只會覺得「顧言帶著東西」，不會聯想到相機在許星棠身上。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠站在工作台另一頭。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有碰假死道具。她在做另一件事。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的真相機掛在脖子上。母親的記憶卡在相機裡。今天拍的基座照片在相機裡。解密後的短版證據包——十五秒版本——已經存進了一張備份卡。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "備份卡不在顧言的背包裡。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "備份卡不在假相機包裡。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "備份卡在她攝影背心的內側口袋裡。貼著身體。拉鏈拉死。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "確認一下。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很平。像在念清單。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "真相機。在我身上。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拍了拍胸前的相機。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "備份卡。在我身上。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拍了拍攝影背心內側。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "短版證據包。已經進了閉幕素材流程。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）閉幕回顧影片備份檔。她用文檔組攝影的權限提交的。檔名是正常格式。沒有人會提前打開看。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "顧言背包裡沒有任何證據。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "假相機包裡只有泡棉。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "邵叔就算拿到假包——打開——裡面什麼都沒有。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）真證據分流。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三條線。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）真相機在星棠身上。她不離開直播備份線附近。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）短版證據包在閉幕素材流程裡。23:00 切換時自動接入。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）備份卡在她身上。就算直播被切，就算相機被搶——備份卡還在。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）而我帶著假包去鐘樓。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔會追餌。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他追餌的時候——星棠接入直播。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把假人推到鐵捲門旁邊。輪子在地上碾過，發出很低的咕嚕聲。他蹲下來，檢查了一遍假人的固定——雨衣、外套、背包、器材袋。每一樣都綁好了。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "22:22 之前我送到鐘樓背面。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "維修庭院。低層平台。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你停電之後從服務走廊走。我在平台那邊放假人。你到的時候它已經在位了。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來，拍了拍手上的灰。手背上的平行刮傷在燈光下閃了一下——暗紅的薄痂。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "不要回頭看。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是安慰。是命令。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "放上去就走。服務走廊通舊器材倉，接禮堂側台卸貨口。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）服務走廊。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是密道。是校慶舞台組搬燈架用過的戶外動線。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）平常上鎖。今天開過。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只能走一次。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了一眼工作台上的東西。筆記本。筆。學生證。面紙。充電線。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這些東西不能帶去鐘樓。背包裡只能放手機——讓邵叔透過手機定位確認「顧言在鐘樓背面」。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把筆記本拿起來。翻到最後一頁。看了一眼那六行字。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能讓他知道我還活著。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）最後一輪，讓他以為我死了。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）證據必須出去。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）星棠必須活過 23:00。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把筆記本放回工作台上。不帶了。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不需要了。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）計畫在腦子裡。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）剩下的——交給身體。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠走過來。她沒有看假人。她在看顧言。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "手機放進背包之後，你就看不到時間了。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "23:01 用我的手機。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機從口袋裡拿出來。螢幕亮了一下。鎖屏桌布是黑色的。什麼都沒有。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "到時候我舉給你看。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）23:01。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）用她的手機。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是我的。我的在假死道具裡。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他點了一下頭。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "好。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把鐵捲門往下拉了一半。雨聲從大到小。倉庫裡的燈光在潮濕的空氣裡發黃。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "21:45。監控切線。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那時候再動。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了顧言一眼。又看了許星棠一眼。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "東西放到定位之前，誰都不要單獨行動。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "命令式。但不是在控制。是在確認每個人都知道下一步。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著工作台上的假人。黑雨衣。舊外套。他的背包。他的手機。裝沙的器材袋。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這些東西加起來，在暴雨和停電裡，在低畫質監控和遠距觀察中——", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "會變成一個人。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個從鐘樓背面掉下去的人。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是要騙所有人。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只要騙一個人。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只要讓他在 22:22 到 23:00 之間——", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）相信我不會再出現。", background: Background.Chapter_8_Ch8_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸了一口氣。倉庫裡的空氣潮濕、沉悶，像吸進了一團濕棉花。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:50。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還有一小時三十二分鐘。", background: Background.Chapter_8_Ch8_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。", background: Background.Chapter_8_Ch8_Act10_S0 },
];
